// src/components/Navbar.js
import React from "react";
import { Link, useNavigate, useLocation } from "react-router-dom";
import { FaUserCircle, FaSignOutAlt } from "react-icons/fa";

function Navbar() {
  const navigate = useNavigate();
  const location = useLocation();
  const userRole = localStorage.getItem("role");

  const handleLogout = () => {
    localStorage.removeItem("role");
    navigate("/");
  };

  return (
    <nav
      className="navbar navbar-expand-lg shadow-sm"
      style={{
        background: "linear-gradient(90deg, #a71010, #7a0c0c)",
        padding: "0.75rem 1.5rem",
        position: "sticky",
        top: 0,
        zIndex: 999,
      }}
    >
      {/* Brand / Logo */}
      <Link
        to="/"
        className="navbar-brand fw-bold text-white d-flex align-items-center"
        style={{ letterSpacing: "1px", fontSize: "1.3rem" }}
      >
        NexaLearn LMS
      </Link>

      <div className="ms-auto d-flex align-items-center gap-3">
        {userRole && (
          <>
            {/* Dashboard Link */}
            <Link
              to={`/${userRole}`}
              className={`text-white text-decoration-none fw-semibold px-3 py-2 rounded ${
                location.pathname === `/${userRole}` ? "bg-white text-dark" : "hover-bg"
              }`}
              style={{ transition: "0.3s" }}
            >
              Dashboard
            </Link>

            {/* User Role Badge */}
            <div
              className="d-flex align-items-center gap-1 px-3 py-2 rounded"
              style={{
                backgroundColor: "rgba(255,255,255,0.2)",
                color: "#fff",
                fontSize: "0.85rem",
                fontWeight: "500",
              }}
            >
              <FaUserCircle style={{ fontSize: "1.2rem" }} />
              <span>{userRole.toUpperCase()}</span>
            </div>

            {/* Logout Button */}
            <button
              onClick={handleLogout}
              className="d-flex align-items-center gap-1 px-3 py-2 btn"
              style={{
                backgroundColor: "#fff",
                color: "#a71010",
                borderRadius: "20px",
                fontWeight: "600",
                transition: "0.3s",
              }}
            >
              <FaSignOutAlt />
              Logout
            </button>
          </>
        )}
      </div>
    </nav>
  );
}

export default Navbar;
